@pytest.mark.skipif(not HAS_TORCH, reason="PyTorch not available")
def test_spectral_ratio_computation():
    """Test spectral ratio computation."""
    model = nn.Sequential(
        nn.Linear(100, 50),
        nn.ReLU(),
        nn.Linear(50, 10),
    )

    ratio, diag = compute_spectral_ratio(model)

    assert isinstance(ratio, float)
    assert ratio > 0
    assert isinstance(diag, dict)

    # Should have diagnostics for linear layers
    for layer_idx, layer_diag in diag.items():
        assert "sigma_1" in layer_diag
        assert "sigma_2" in layer_diag
        assert "ratio" in layer_diag
        assert layer_diag["sigma_1"] >= layer_diag["sigma_2"]


@pytest.mark.skipif(not HAS_TORCH, reason="PyTorch not available")
def test_spectral_ratio_single_layer():
    """Test spectral ratio for specific layer."""
    model = nn.Sequential(
        nn.Linear(100, 50),
        nn.Linear(50, 10),
    )

    ratio, diag = compute_spectral_ratio(model, layer_index=0)

    # Should only have diagnostics for layer 0
    assert len(diag) <= 1


@pytest.mark.skipif(not HAS_TORCH, reason="PyTorch not available")
def test_spectral_ratio_none_model():
    """Test spectral ratio with None model (should return default)."""
    ratio, diag = compute_spectral_ratio(None)

    assert ratio == 2.0
    assert diag == {}


# ============================================================================
# Integration Tests
# ============================================================================


def test_end_to_end_workflow():
    """Test complete workflow: calculator → scheduler."""
    # Step 1: Compute optimal LR from architecture
    calc = ResonanceFrequencyCalculator(3072, 32, 32, 8192)
    optimal_lr = calc.compute_optimal_learning_rate(num_training_steps=1000)

    assert 1e-6 <= optimal_lr <= 1e-2

    # Step 2: Create scheduler with computed LR
    scheduler = AdaptiveResonanceLRScheduler(
        base_lr=optimal_lr,
        target_sigma_ratio=2.0,
        enable_resonance_tuning=True,
    )

    assert scheduler.base_lr == optimal_lr

    # Step 3: Simulate training
    losses = [2.0 * math.exp(-i / 200) + 0.1 for i in range(500)]

    for i, loss in enumerate(losses):
        sigma_ratio = 2.0 + 0.1 * math.sin(i / 50)
        metrics = scheduler.step(loss, [sigma_ratio] * 32)

        assert metrics.step == i + 1
        assert metrics.loss == loss

    # Step 4: Verify scheduler state
    diag = scheduler.get_diagnostics()
    assert diag["step_count"] == 500
    assert diag["min_loss"] < diag["max_loss"]


# ============================================================================
# Main (for running without pytest)
# ============================================================================


def run_tests_without_pytest():
    """Run tests manually if pytest is not available."""
    print("Running tests without pytest...")

    tests = [
        test_calculator_initialization,
        test_resonance_frequency_computation,
        test_optimal_learning_rate_computation,
        test_calculator_diagnostics,
        test_scheduler_initialization,
        test_scheduler_phase_transition,
        test_scheduler_learning_rate_adjustment,
        test_scheduler_metrics_export,
        test_scheduler_diagnostics,
        test_end_to_end_workflow,
    ]

    passed = 0
    failed = 0

    for test_func in tests:
        try:
            test_func()
            print(f"✓ {test_func.__name__}")
            passed += 1
        except Exception as e:
            print(f"✗ {test_func.__name__}: {e}")
            failed += 1

    print(f"\n{passed} passed, {failed} failed")
    return failed == 0


if __name__ == "__main__":
    if HAS_PYTEST:
        pytest.main([__file__, "-v"])
    else:
        success = run_tests_without_pytest()
        sys.exit(0 if success else 1)
